# Training loop with S3 checkpointing
def train_with_checkpoints(model, optimizer, dataloader, checkpoint_interval=100):
    for epoch in range(num_epochs):
        for step, batch in enumerate(dataloader):
            # ... training logic ...
            if step % checkpoint_interval == 0:
                torch.save({
                    'epoch': epoch, 'step': step,
                    'model_state_dict': model.state_dict(),
                    'optimizer_state_dict': optimizer.state_dict(),
                }, f's3://checkpoints/model_{epoch}_{step}.pt')

#!/bin/bash # Find idle EC2 instances: avg CPU < 5% over 7 days INSTANCES=$(aws ec2 describe-instances \ --filters "Name=instance-state-name,Values=running" \ --query "Reservations[].Instances[].InstanceId" --output text)
for INSTANCE_ID in $INSTANCES; do AVG_CPU=$(aws cloudwatch get-metric-statistics \ --namespace AWS/EC2 --metric-name CPUUtilization \ --dimensions Name=InstanceId,Value=$INSTANCE_ID \ --start-time $(date -d '7 days ago' --iso-8601=seconds) \ --end-time $(date --iso-8601=seconds) \ --period 86400 --statistics Average \ --query 'Datapoints[].Average | avg(@)' --output text)
if (( $(echo "$AVG_CPU < 5" | bc -l) )); then echo "IDLE: $INSTANCE_ID (Avg CPU: $AVG_CPU%)" fi done
